'use client'

import { useEffect } from 'react'
import { IconSearch } from '@tabler/icons-react'

interface MobileSearchDrawerProps {
    isOpen: boolean
    onClose: () => void
    query: string
    onQueryChange: (query: string) => void
    resultCount: number
}

export function MobileSearchDrawer({ isOpen, onClose, query, onQueryChange, resultCount }: MobileSearchDrawerProps) {
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden'
        } else {
            document.body.style.overflow = 'unset'
        }
        return () => {
            document.body.style.overflow = 'unset'
        }
    }, [isOpen])

    if (!isOpen) return null

    return (
        <>
            <div
                className="fixed inset-0 bg-black/50 z-50 md:hidden"
                onClick={onClose}
            />
            <div className="fixed bottom-0 left-0 right-0 z-50 md:hidden">
                <div className="bg-background border-t border-border p-6 animate-in slide-in-from-bottom duration-200">
                    <div className="relative">
                        <IconSearch className="absolute left-0 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder="Search posts..."
                            value={query}
                            onChange={(e) => onQueryChange(e.target.value)}
                            autoFocus
                            className="w-full border-0 border-b border-border bg-transparent pl-6 pr-6 py-3 text-base placeholder:text-muted-foreground focus:border-foreground focus:outline-none focus:ring-0"
                        />
                    </div>
                    {query && (
                        <p className="mt-3 text-sm text-muted-foreground">
                            {resultCount} result{resultCount !== 1 ? 's' : ''} found
                        </p>
                    )}
                </div>
            </div>
        </>
    )
}

import { create, insert, search } from '@orama/orama'
import type { PostWithMeta } from './blog'

export type { PostWithMeta }

export type PostSearchResult = {
    id: string
    slug: string
    title: string
    description: string
    date?: string
    readingTime: number
    tags?: string[]
}

export type DisplayablePost = PostWithMeta

interface OramaDocument {
    slug: string
    title: string
    description: string
    content: string
    date: string
    readingTime: number
    tags: string
}

interface OramaSearchParams {
    term: string
    limit: number
}

interface OramaHit {
    document: OramaDocument
}

interface OramaSearchResult {
    hits: OramaHit[]
}

let searchIndex: ReturnType<typeof create> | null = null

const postSchema = {
    slug: 'string',
    title: 'string',
    description: 'string',
    content: 'string',
    date: 'string',
    readingTime: 'number',
    tags: 'string',
} as const

let cachedPosts: PostWithMeta[] | null = null

export async function initializeSearch(posts: PostWithMeta[]) {
    const postsKey = posts.map(p => p.slug).join(',')

    if (searchIndex && cachedPosts && cachedPosts.map(p => p.slug).join(',') === postsKey) {
        return searchIndex
    }

    searchIndex = create({
        schema: postSchema,
    })

    for (const post of posts) {
        const dateValue = post.frontmatter.date as unknown
        const dateStr = dateValue && typeof dateValue === 'object' && 'toISOString' in dateValue
            ? (dateValue as Date).toISOString()
            : String(dateValue || '')

        await insert(searchIndex, {
            slug: post.slug,
            title: post.frontmatter.title || '',
            description: post.frontmatter.description || '',
            content: post.content,
            date: dateStr,
            readingTime: post.readingTime,
            tags: post.frontmatter.tags?.join(' ') || '',
        })
    }

    cachedPosts = posts
    return searchIndex
}

export async function searchPosts(
    query: string,
    posts: PostWithMeta[],
    limit: number = 10
): Promise<PostWithMeta[]> {
    if (!query.trim()) {
        return posts
    }

    const index = await initializeSearch(posts)

    const results: OramaSearchResult = await search(index, {
        term: query,
        limit,
    } as OramaSearchParams)

    return results.hits.map((hit: OramaHit): PostWithMeta => ({
        slug: hit.document.slug,
        frontmatter: {
            title: hit.document.title,
            description: hit.document.description,
            date: hit.document.date,
            tags: hit.document.tags?.split(' ').filter(Boolean),
        },
        content: '',
        readingTime: hit.document.readingTime,
    }))
}

